"""Private browser LiveOps dashboard and founder notification endpoints."""
from fastapi import APIRouter, Depends
from fastapi.responses import HTMLResponse
from .services.admin_auth import require_admin_token
from .services import founder_notifications, live_ops_service

router = APIRouter(prefix="/admin")

@router.get("/live-ops/funnel")
async def live_ops_funnel(_: str = Depends(require_admin_token)):
    return await live_ops_service.funnel_summary()

@router.post("/live-ops/funnel/reset")
async def live_ops_reset(_: str = Depends(require_admin_token)):
    return await live_ops_service.reset_funnel()

@router.get("/founder-notifications/status")
async def founder_notification_status(_: str = Depends(require_admin_token)):
    return await founder_notifications.status()

@router.post("/founder-notifications/test")
async def founder_notification_test(_: str = Depends(require_admin_token)):
    return await founder_notifications.send_test_notification()

@router.get("/live-ops/funnel-dashboard", response_class=HTMLResponse)
async def live_ops_dashboard():
    return HTMLResponse(DASHBOARD_HTML)

DASHBOARD_HTML = '<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>DeepPrep LiveOps - ThoughtSnap Labs</title><style>:root{color-scheme:dark;--bg:#050816;--panel:#0d1328;--line:#26314f;--text:#f7f8ff;--muted:#aab4d4;--blue:#66d9ff;--green:#38e8a8;--amber:#ffd166;--red:#ff5c7a}*{box-sizing:border-box}body{margin:0;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,Arial,sans-serif;background:radial-gradient(circle at top left,#16275d 0,#050816 44%,#02030a 100%);color:var(--text)}.wrap{max-width:1180px;margin:0 auto;padding:18px}.top{display:flex;justify-content:space-between;gap:16px;align-items:flex-start;margin-bottom:18px}.kicker{color:var(--blue);letter-spacing:.14em;text-transform:uppercase;font-size:12px;font-weight:800}h1{margin:4px 0 0;font-size:32px;letter-spacing:-.04em}.sub{color:var(--muted);font-size:14px;line-height:1.4}.auth,.panel,.card{background:rgba(13,19,40,.88);border:1px solid var(--line);border-radius:18px;box-shadow:0 16px 48px rgba(0,0,0,.22)}.auth{padding:12px;min-width:310px}input{width:100%;background:#070b19;border:1px solid var(--line);color:var(--text);border-radius:12px;padding:12px;font-size:15px}button{border:0;border-radius:12px;padding:11px 13px;color:#041018;background:var(--blue);font-weight:800;cursor:pointer}.secondary{background:#1a2445;color:var(--text);border:1px solid var(--line)}.row{display:flex;gap:8px;margin-top:8px}.status{margin-top:8px;color:var(--muted);font-size:12px}.cards{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:12px}.card{padding:14px;min-height:96px}.label{color:var(--muted);font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:.08em}.value{font-size:28px;font-weight:900;margin-top:9px;letter-spacing:-.04em}.green{color:var(--green)}.amber{color:var(--amber)}.blue{color:var(--blue)}.grid2{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-top:12px}.panel{padding:14px;overflow:auto}.panel h2{margin:0 0 12px;font-size:18px}table{width:100%;border-collapse:collapse;font-size:13px}th,td{text-align:left;padding:10px 8px;border-bottom:1px solid rgba(38,49,79,.7);vertical-align:top}th{color:var(--muted);font-size:11px;text-transform:uppercase;letter-spacing:.08em}.pill{display:inline-flex;border:1px solid var(--line);background:#0a1024;border-radius:999px;padding:4px 8px;font-size:12px;color:var(--muted)}.event{color:var(--blue);font-weight:800}.footer{color:var(--muted);font-size:12px;margin-top:14px;text-align:center}@media(max-width:900px){.top{flex-direction:column}.auth{width:100%;min-width:0}.cards{grid-template-columns:repeat(2,minmax(0,1fr))}.grid2{grid-template-columns:1fr}}@media(max-width:520px){.cards{grid-template-columns:1fr}.wrap{padding:12px}.value{font-size:25px}table{font-size:12px}th,td{padding:8px 5px}}</style></head><body><div class="wrap"><div class="top"><div><div class="kicker">ThoughtSnap Labs LiveOps</div><h1>DeepPrep Command Centre</h1><div class="sub">Rolling launch metrics, VAP, deduped purchases and founder sale notifications. Refreshes every 15 seconds.</div></div><div class="auth"><input id="token" placeholder="x-admin-token" type="password"><div class="row"><button onclick="saveToken()">Unlock</button><button class="secondary" onclick="testNotify()">Send Test Notification</button></div><div id="status" class="status">Enter your admin token to load LiveOps.</div></div></div><div id="cards" class="cards"></div><div class="grid2"><div class="panel"><h2>Conversion Funnel</h2><div id="funnel"></div></div><div class="panel"><h2>Purchase History</h2><div id="purchases"></div></div></div><div class="panel" style="margin-top:12px"><h2>Recent Events</h2><div id="events"></div></div><div class="footer">DeepPrep - Browser-only admin - No app UI - Raw events remain untouched</div></div><script>const tokenInput=document.getElementById(\'token\');tokenInput.value=localStorage.getItem(\'deepprep_admin_token\')||\'\';function money(v){return \'£\'+Number(v||0).toFixed(2)}function pct(v){return Number(v||0).toFixed(1)+\'%\'}function time(v){if(!v)return \'—\';try{return new Date(v).toLocaleString()}catch{return v}}function token(){return tokenInput.value.trim()}function saveToken(){localStorage.setItem(\'deepprep_admin_token\',token());load()}async function api(path,opts={}){const res=await fetch(path,{...opts,headers:{...(opts.headers||{}),\'x-admin-token\':token(),\'content-type\':\'application/json\'}});if(!res.ok)throw new Error(res.status+\' \'+await res.text());return res.json()}function card(l,v,t=\'\'){return `<div class="card"><div class="label">${l}</div><div class="value ${t}">${v}</div></div>`}function table(h,rows){return `<table><thead><tr>${h.map(x=>`<th>${x}</th>`).join(\'\')}</tr></thead><tbody>${rows.join(\'\')||`<tr><td colspan="${h.length}"><span class="pill">No data yet</span></td></tr>`}</tbody></table>`}async function testNotify(){try{document.getElementById(\'status\').textContent=\'Sending test notification...\';const r=await api(\'/api/admin/founder-notifications/test\',{method:\'POST\',body:\'{}\'});document.getElementById(\'status\').textContent=r.ok?\'Test notification sent.\':\'Test failed: \'+JSON.stringify(r.result||r)}catch(e){document.getElementById(\'status\').textContent=\'Test failed: \'+e.message}}async function load(){if(!token())return;try{const d=await api(\'/api/admin/live-ops/funnel\');const c=d.cards||{};document.getElementById(\'status\').textContent=`Live - Updated ${time(d.generatedAt)} - Since ${new Date(d.launchDate).toLocaleDateString()}`;document.getElementById(\'cards\').innerHTML=[card(\'Onboarding Started\',c.onboardingStarted??0,\'blue\'),card(\'Onboarding Completion\',pct(c.onboardingCompletionRate),\'green\'),card(\'Paywall Conversion\',pct(c.paywallConversionRate),\'amber\'),card(\'Weekly Sales\',c.weeklySales??0,\'green\'),card(\'Annual Sales\',c.annualSales??0,\'green\'),card(\'Monthly Sales\',c.monthlySales??0,\'green\'),card(\'Lifetime Sales\',c.lifetimeSales??0,\'green\'),card(\'Gross Revenue\',money(c.grossRevenue),\'green\'),card(\'Net Revenue (-15%)\',money(c.netRevenue),\'green\'),card(\'Live Events 30m\',c.liveEvents30m??0,\'blue\'),card(\'Global VAP Today\',c.globalVapToday??0,\'blue\'),card(\'VAP Since Launch\',c.globalVapSinceLaunch??0,\'blue\'),card(\'Total Purchases\',c.totalPurchases??0,\'green\'),card(\'Last Purchase\',c.lastPurchaseTime?time(c.lastPurchaseTime):\'—\',\'amber\')].join(\'\');document.getElementById(\'funnel\').innerHTML=table([\'Step\',\'Count\'],(d.conversionFunnel||[]).map(x=>`<tr><td>${x.label}</td><td><strong>${x.count}</strong></td></tr>`));document.getElementById(\'purchases\').innerHTML=table([\'Time\',\'Device\',\'Plan\',\'Gross\',\'Net\',\'Source\'],(d.purchaseHistory||[]).slice(0,40).map(p=>`<tr><td>${time(p.time)}</td><td>${p.maskedDeviceId}</td><td>${p.planLabel}<br><span class="pill">${p.productId}</span></td><td>${money(p.gross)}</td><td>${money(p.net)}</td><td>${p.source}</td></tr>`));document.getElementById(\'events\').innerHTML=table([\'Time\',\'Event\',\'Device\',\'Source\',\'VAP\'],(d.recentEvents||[]).slice(0,80).map(e=>`<tr><td>${time(e.time)}</td><td class="event">${e.eventType}</td><td>${e.maskedDeviceId}</td><td>${e.source}</td><td>${e.vap}</td></tr>`))}catch(e){document.getElementById(\'status\').textContent=\'Error: \'+e.message}}setInterval(load,15000);load();</script></body></html>'
